import { TOPICS } from "../data/topicsData";
import { getCompletedTopics, getQuizScores, clearProgress } from "../utils/progress";

// ─── Stat Card ────────────────────────────────────────────────────────────────
function StatCard({ value, label, sublabel, color = "#6366f1" }) {
  return (
    <div
      className="glass p-5 text-center"
      style={{ border: `1px solid ${color}20` }}
    >
      <p
        className="text-3xl font-bold mb-0.5"
        style={{ color, textShadow: `0 0 16px ${color}40` }}
      >
        {value}
      </p>
      <p className="text-sm text-slate-300 font-medium">{label}</p>
      {sublabel && <p className="text-xs text-slate-500 mt-0.5">{sublabel}</p>}
    </div>
  );
}

// ─── AI Suggestions Panel ─────────────────────────────────────────────────────
function AISuggestions({ quizScores, completedTopics }) {
  const [suggestion, setSuggestion] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [fetched, setFetched] = useState(false);

  const fetchSuggestions = async () => {
    setLoading(true);
    setError(null);

    // Build a compact summary of performance for the prompt
    const topicSummaries = quizScores.reduce((acc, s) => {
      if (!acc[s.topic]) acc[s.topic] = { attempts: 0, totalPct: 0 };
      acc[s.topic].attempts += 1;
      acc[s.topic].totalPct += Math.round((s.score / s.total) * 100);
      return acc;
    }, {});

    const performanceLines = Object.entries(topicSummaries).map(
      ([topic, data]) =>
        `- ${topic}: avg ${Math.round(data.totalPct / data.attempts)}% over ${data.attempts} attempt(s)`
    );

    const notStarted = TOPICS
      .filter(t => !completedTopics.includes(t.slug))
      .map(t => t.name)
      .slice(0, 8); // cap list size

    const prompt = `You are a friendly aptitude exam coach. A student has shared their quiz performance below.

Quiz performance:
${performanceLines.length > 0 ? performanceLines.join("\n") : "No quizzes taken yet."}

Topics not yet studied: ${notStarted.length > 0 ? notStarted.join(", ") : "All topics have been started."}

Give a SHORT (3-4 sentences max), encouraging, and specific study plan. Mention:
1. The 1-2 weakest topics they should re-practice (below 60%) or an untried topic if no weak areas exist.
2. One concrete tip for improvement.
3. What they're doing well (if applicable).

Be warm, direct, and actionable. Do NOT use bullet points or headers — write in plain prose.`;

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await res.json();
      const text = data.content?.map(b => b.text || "").join("") || "";
      if (!text) throw new Error("Empty response from AI");
      setSuggestion(text.trim());
      setFetched(true);
    } catch (err) {
      setError("Couldn't load suggestions right now. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <section
      className="glass mb-5 overflow-hidden animate-fade-up-d3"
      style={{ border: "1px solid rgba(99,102,241,0.2)" }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-3.5"
        style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
      >
        <div className="flex items-center gap-2">
          <span style={{ fontSize: "1rem" }}>✨</span>
          <p className="section-label" style={{ color: "#a5b4fc" }}>AI Study Coach</p>
        </div>
        {!fetched && !loading && (
          <button
            onClick={fetchSuggestions}
            style={{
              padding: "5px 14px",
              borderRadius: 8,
              border: "1px solid rgba(99,102,241,0.4)",
              background: "rgba(99,102,241,0.12)",
              color: "#a5b4fc",
              fontSize: "0.72rem",
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            Get suggestions →
          </button>
        )}
        {fetched && !loading && (
          <button
            onClick={fetchSuggestions}
            style={{
              padding: "5px 14px",
              borderRadius: 8,
              border: "1px solid rgba(255,255,255,0.08)",
              background: "transparent",
              color: "#475569",
              fontSize: "0.72rem",
              cursor: "pointer",
            }}
          >
            Refresh
          </button>
        )}
      </div>

      <div className="px-5 py-4">
        {/* Idle state */}
        {!fetched && !loading && !error && (
          <p className="text-slate-500 text-sm">
            Get a personalised study plan based on your quiz history.
          </p>
        )}

        {/* Loading */}
        {loading && (
          <div className="flex items-center gap-3 py-2">
            <div style={{
              width: 18, height: 18, borderRadius: "50%",
              border: "2px solid rgba(99,102,241,0.3)",
              borderTop: "2px solid #6366f1",
              animation: "spin 0.8s linear infinite",
            }} />
            <p className="text-sm text-slate-400">Analysing your performance…</p>
          </div>
        )}

        {/* Error */}
        {error && !loading && (
          <p className="text-sm" style={{ color: "#f87171" }}>{error}</p>
        )}

        {/* Suggestion */}
        {suggestion && !loading && (
          <p
            className="text-sm leading-relaxed"
            style={{ color: "#c7d2fe", lineHeight: 1.7 }}
          >
            {suggestion}
          </p>
        )}
      </div>

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </section>
  );
}

// ─── Main Progress Page ───────────────────────────────────────────────────────
export default function Progress() {
  const [completed, setCompleted] = useState(getCompletedTopics());
  const [quizScores, setQuizScores] = useState(getQuizScores());

  // Re-sync from storage whenever the tab regains focus (e.g. after finishing a quiz)
  useEffect(() => {
    const onFocus = () => {
      setCompleted(getCompletedTopics());
      setQuizScores(getQuizScores());
    };
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, []);

  const handleClear = () => {
    if (window.confirm("Clear all progress data? This cannot be undone.")) {
      clearProgress();
      setCompleted([]);
      setQuizScores([]);
    }
  };

  const pctDone = Math.round((completed.length / TOPICS.length) * 100);
  const avgScore =
    quizScores.length > 0
      ? Math.round(
          quizScores.reduce((sum, s) => sum + (s.score / s.total) * 100, 0) /
            quizScores.length
        )
      : null;

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      {/* Header */}
      <div className="mb-8 animate-fade-up">
        <span className="section-label glow-dot">Your Progress</span>
        <h1 className="text-2xl font-bold text-white mt-2 mb-1" style={{ letterSpacing: "-0.01em" }}>
          Learning Dashboard
        </h1>
        <p className="text-slate-400 text-sm">Track your activity across all AptiPrep topics.</p>
      </div>

      {/* Stat cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 mb-6 animate-fade-up-d1">
        <StatCard
          value={`${completed.length}/${TOPICS.length}`}
          label="Topics Viewed"
          sublabel={`${pctDone}% complete`}
          color="#6366f1"
        />
        <StatCard
          value={quizScores.length}
          label="Quizzes Taken"
          color="#38bdf8"
        />
        {avgScore !== null && (
          <StatCard
            value={`${avgScore}%`}
            label="Avg Score"
            sublabel="across all quizzes"
            color={avgScore >= 70 ? "#22c55e" : avgScore >= 50 ? "#f59e0b" : "#ef4444"}
          />
        )}
      </div>

      {/* Progress bar */}
      <div className="glass p-4 mb-6 animate-fade-up-d2">
        <div className="flex items-center justify-between mb-2">
          <span className="section-label">Overall Progress</span>
          <span className="text-xs font-mono" style={{ color: "#6366f1" }}>{pctDone}%</span>
        </div>
        <div className="progress-track">
          <div className="progress-fill" style={{ width: `${pctDone}%` }} />
        </div>
      </div>

      {/* ── AI Study Coach ── */}
      <AISuggestions quizScores={quizScores} completedTopics={completed} />

      {/* Completed topics */}
      <section className="glass mb-5 overflow-hidden animate-fade-up-d3">
        <div
          className="flex items-center justify-between px-5 py-3.5"
          style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
        >
          <p className="section-label">Topics Viewed</p>
          <span className="text-xs font-mono" style={{ color: "#475569" }}>
            {completed.length}/{TOPICS.length}
          </span>
        </div>

        {completed.length === 0 ? (
          <div className="px-5 py-8 text-center">
            <p className="text-slate-500 text-sm mb-3">No topics viewed yet.</p>
            <Link to="/" className="btn-primary text-xs" style={{ padding: "8px 16px", display: "inline-block" }}>
              Start Learning →
            </Link>
          </div>
        ) : (
          <ul className="list-none m-0 p-0">
            {TOPICS.filter((t) => completed.includes(t.slug)).map((t) => (
              <li key={t.slug} className="topic-row last:border-0">
                <Link
                  to={`/topic/${t.slug}`}
                  className="flex items-center justify-between px-5 py-3 group no-underline"
                >
                  <span className="text-sm text-slate-300 group-hover:text-white transition-colors font-medium">
                    {t.name}
                  </span>
                  <div className="flex items-center gap-2">
                    <span className="badge badge-green">✓ done</span>
                    <span className="text-slate-600 group-hover:text-primary transition-colors text-xs">→</span>
                  </div>
                </Link>
              </li>
            ))}
          </ul>
        )}
      </section>

      {/* Quiz history */}
      <section className="glass mb-6 overflow-hidden animate-fade-up-d3">
        <div
          className="flex items-center justify-between px-5 py-3.5"
          style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
        >
          <p className="section-label">Quiz History</p>
          <span className="text-xs font-mono" style={{ color: "#475569" }}>
            {quizScores.length} taken
          </span>
        </div>

        {quizScores.length === 0 ? (
          <div className="px-5 py-8 text-center">
            <p className="text-slate-500 text-sm mb-3">No quizzes taken yet.</p>
            <Link to="/quiz" className="btn-accent text-xs" style={{ padding: "8px 16px", display: "inline-block" }}>
              Take a Quiz →
            </Link>
          </div>
        ) : (
          <ul className="list-none m-0 p-0">
            {[...quizScores].reverse().map((s, i) => {
              const pct = Math.round((s.score / s.total) * 100);
              const scoreColor =
                pct >= 80 ? "#22c55e" : pct >= 50 ? "#f59e0b" : "#ef4444";
              return (
                <li
                  key={i}
                  className="flex items-center justify-between px-5 py-3.5"
                  style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}
                >
                  <div>
                    <p className="text-sm text-slate-300 font-medium">{s.topic}</p>
                    <p className="text-xs text-slate-500 mt-0.5">
                      {new Date(s.date).toLocaleDateString("en-IN", {
                        day: "numeric", month: "short", year: "numeric",
                      })}
                    </p>
                  </div>
                  <div className="text-right">
                    <p
                      className="text-sm font-bold font-mono"
                      style={{ color: scoreColor }}
                    >
                      {s.score}/{s.total}
                    </p>
                    <p className="text-xs" style={{ color: scoreColor }}>{pct}%</p>
                  </div>
                </li>
              );
            })}
          </ul>
        )}
      </section>

      {/* Clear button */}
      <button
        onClick={handleClear}
        className="text-xs text-slate-600 hover:text-red-400 transition-colors"
      >
        Clear all progress data
      </button>

      <div className="h-16" />
    </main>
  );
}
